section("Quoted Fields");

test("handles quoted fields with commas inside", () => {
  const csv = `name,address
Alice,"123 Main St, Apt 4"
Bob,"456 Oak Ave, Suite 10"`;
  const result = parseCSV(csv);
  assertEqual(result.rows[0]["address"], "123 Main St, Apt 4", "address with comma");
  assertEqual(result.rows[1]["address"], "456 Oak Ave, Suite 10", "second address");
});

test("handles quoted fields without special chars", () => {
  const csv = `a,b
"hello","world"`;
  const result = parseCSV(csv);
  assertEqual(result.rows[0]["a"], "hello", "quoted a");
  assertEqual(result.rows[0]["b"], "world", "quoted b");
});

test("handles mixed quoted and unquoted fields", () => {
  const csv = `a,b,c
hello,"wor,ld",foo`;
  const result = parseCSV(csv);
  assertEqual(result.rows[0]["a"], "hello", "unquoted a");
  assertEqual(result.rows[0]["b"], "wor,ld", "quoted b with comma");
  assertEqual(result.rows[0]["c"], "foo", "unquoted c");
});

test("handles quoted fields spanning multiple lines", () => {
  const csv = `name,bio
Alice,"Line one
Line two"
Bob,Simple`;
  const result = parseCSV(csv);
  assertEqual(result.rows.length, 2, "two rows");
  assertEqual(result.rows[0]["bio"], "Line one\nLine two", "multiline field");
  assertEqual(result.rows[1]["bio"], "Simple", "simple field");
});

test("handles quoted field that is entirely empty inside quotes", () => {
  const csv = `a,b
"",hello`;
  const result = parseCSV(csv);
  // Empty quoted field → empty string → coerced to null
  assertEqual(result.rows[0]["a"], null, "empty quoted → null");
  assertEqual(result.rows[0]["b"], "hello", "normal field");
});

