});

test("parses semicolon-separated values", () => {
  const csv = "a;b;c\n1;2;3\n4;5;6";
  const result = parseCSV(csv, { delimiter: ";" });
  assertEqual(result.rows[0]["a"], 1, "first val");
  assertEqual(result.rows[1]["c"], 6, "last val");
});

test("parses pipe-separated values", () => {
  const csv = "x|y\nhello|world";
  const result = parseCSV(csv, { delimiter: "|" });
  assertEqual(result.rows[0]["x"], "hello", "x");
  assertEqual(result.rows[0]["y"], "world", "y");
});

test("custom quote character (single quote)", () => {
  const csv = "a,b\n'hello, world',test";
  const result = parseCSV(csv, { quote: "'" });
  assertEqual(result.rows[0]["a"], "hello, world", "single-quoted with comma");
  assertEqual(result.rows[0]["b"], "test", "normal field");
});

test("custom line separator", () => {
  const csv = "a,b|1,2|3,4";
  const result = parseCSV(csv, { lineSeparator: "|" });
  assertEqual(result.rows.length, 2, "two rows");
  assertEqual(result.rows[0]["a"], 1, "first row");
  assertEqual(result.rows[1]["b"], 4, "second row");
});

test("custom delimiter + custom quote together", () => {
  const csv = "a;b\n'one;two';three";
  const result = parseCSV(csv, { delimiter: ";", quote: "'" });
  assertEqual(result.rows[0]["a"], "one;two", "quoted field with delimiter inside");
  assertEqual(result.rows[0]["b"], "three", "normal field");
});

// ============================================================================
// 5. TYPE COERCION
// ============================================================================
section("Type Coercion");

test("coerces integers", () => {
  const csv = "val\n0\n42\n-7\n1000000";
  const result = parseCSV(csv);
  assertEqual(result.rows[0]["val"], 0, "zero");
  assertEqual(result.rows[1]["val"], 42, "positive int");
  assertEqual(result.rows[2]["val"], -7, "negative int");
  assertEqual(result.rows[3]["val"], 1000000, "large int");
});

test("coerces floats", () => {
  const csv = "val\n3.14\n-0.5\n.25\n1.0";
  const result = parseCSV(csv);
  assertAlmostEqual(result.rows[0]["val"] as number, 3.14, 0.001, "pi");
  assertAlmostEqual(result.rows[1]["val"] as number, -0.5, 0.001, "negative float");
  assertAlmostEqual(result.rows[2]["val"] as number, 0.25, 0.001, "leading dot");
  assertAlmostEqual(result.rows[3]["val"] as number, 1.0, 0.001, "trailing zero");
});

test("coerces scientific notation", () => {
  const csv = "val\n1e5\n2.5E-3\n-1.2e+4";
  const result = parseCSV(csv);
  assertEqual(result.rows[0]["val"], 100000, "1e5");
  assertAlmostEqual(result.rows[1]["val"] as number, 0.0025, 0.0001, "2.5E-3");
  assertEqual(result.rows[2]["val"], -12000, "-1.2e+4");
});

test("coerces booleans (case-insensitive)", () => {
  const csv = "val\ntrue\nfalse\nTRUE\nFALSE\nTrue\nFalse";
  const result = parseCSV(csv);
  assertEqual(result.rows[0]["val"], true, "true");
  assertEqual(result.rows[1]["val"], false, "false");
  assertEqual(result.rows[2]["val"], true, "TRUE");
  assertEqual(result.rows[3]["val"], false, "FALSE");
  assertEqual(result.rows[4]["val"], true, "True");
  assertEqual(result.rows[5]["val"], false, "False");
});

test("coerces null values", () => {
  const csv = "a,b,c\nnull,NULL,";
  const result = parseCSV(csv);
  assertEqual(result.rows[0]["a"], null, "null lowercase");
  assertEqual(result.rows[0]["b"], null, "NULL uppercase");
  assertEqual(result.rows[0]["c"], null, "empty string → null");
});

test("preserves strings that look numeric-ish but aren't", () => {
  const csv = "val\n12abc\nhello\n  \n0x1F";
  const result = parseCSV(csv);
  assertEqual(result.rows[0]["val"], "12abc", "alphanumeric");
  assertEqual(result.rows[1]["val"], "hello", "word");
  // "  " (whitespace only) isn't empty but also doesn't match number regex
  // Actually "  ".trim() === "" but coerceValue receives "  " which isn't === ""
  // so it falls through. Let's check:
  assertEqual(typeof result.rows[2]["val"], "string", "whitespace stays string");
  assertEqual(result.rows[3]["val"], "0x1F", "hex stays string");
});

test("type coercion can be disabled", () => {
  const csv = "a,b,c\n42,true,null";
  const result = parseCSV(csv, { typeCoercion: false });
  assertEqual(result.rows[0]["a"], "42", "number stays string");
  assertEqual(result.rows[0]["b"], "true", "boolean stays string");
  assertEqual(result.rows[0]["c"], "null", "null stays string");
});

test("coercion with mixed types in same column", () => {
  const csv = "val\n1\nhello\ntrue\nnull\n3.5";
  const result = parseCSV(csv);
  assertEqual(result.rows[0]["val"], 1, "number");
  assertEqual(result.rows[1]["val"], "hello", "string");
  assertEqual(result.rows[2]["val"], true, "boolean");
  assertEqual(result.rows[3]["val"], null, "null");
  assertAlmostEqual(result.rows[4]["val"] as number, 3.5, 0.001, "float");
});

// ============================================================================
// 6. ERROR HANDLING – MALFORMED ROWS
// ============================================================================
section("Error Handling");

test("collects error for row with too few fields", () => {
  const csv = "a,b,c\n1,2\n3,4,5";
  const result = parseCSV(csv);
  assert(result.errors.length > 0, "should have errors");
  assert(result.errors.some((e) => e.row === 1), "error on row 1");
  assert(
    result.errors.some((e) => e.message.includes("Expected 3 fields but got 2")),
    "message mentions field count"
  );
  // Row should still be included (best-effort)
  assertEqual(result.rows.length, 2, "both rows present");
  assertEqual(result.rows[0]["c"], null, "missing field padded with null");
});

test("collects error for row with too many fields", () => {
  const csv = "a,b\n1,2,3";
  const result = parseCSV(csv);
  assert(result.errors.length > 0, "should have errors");
  assert(
    result.errors.some((e) => e.message.includes("Expected 2 fields but got 3")),
    "message about extra fields"
  );
  // Row is still included but extra fields are truncated to header count
  assertEqual(result.rows.length, 1, "row present");
  assertEqual(result.rows[0]["a"], 1, "a value");
  assertEqual(result.rows[0]["b"], 2, "b value");
});

test("collects error for unterminated quoted field", () => {
  const csv = `a,b
"hello,world`;
  const result = parseCSV(csv);
  assert(result.errors.length > 0, "should have errors");
  assert(
    result.errors.some((e) => e.message.includes("Unterminated")),
    "mentions unterminated"
  );
});

test("parser does not crash on malformed input", () => {
  const csv = `a,b,c
1,2,3
"bad
4,5,6
"worse""
7,8,9`;
  // Should not throw
  const result = parseCSV(csv);
  assert(result.rows.length > 0, "some rows parsed");
  assert(result.errors.length > 0, "errors collected");
});

test("errors include correct row numbers", () => {
  const csv = "a,b\n1,2\n3\n4,5\n6";
  const result = parseCSV(csv);
  const errorRows = result.errors.map((e) => e.row);
  assert(errorRows.includes(2), "row 2 has error (too few fields)");
  assert(errorRows.includes(4), "row 4 has error (too few fields)");
});

test("multiple errors collected across different rows", () => {
  const csv = "a,b,c\n1\n2\n3,4,5";
  const result = parseCSV(csv);
  assert(result.errors.length >= 2, "at least 2 errors");
});

