// 7. FILTERING
// ============================================================================
section("Filtering");

test("filter returns matching rows", () => {
  const csv = "name,age\nAlice,30\nBob,25\nCharlie,35";
  const result = parseCSV(csv);
  const filtered = result.filter((row) => (row["age"] as number) > 28);
  assertEqual(filtered.length, 2, "two matches");
  assertEqual(filtered[0]["name"], "Alice", "Alice matches");
  assertEqual(filtered[1]["name"], "Charlie", "Charlie matches");
});

test("filter returns empty array when nothing matches", () => {
  const csv = "a\n1\n2\n3";
  const result = parseCSV(csv);
  const filtered = result.filter((row) => (row["a"] as number) > 100);
  assertEqual(filtered.length, 0, "no matches");
});

test("filter returns all rows when everything matches", () => {
  const csv = "a\n1\n2\n3";
  const result = parseCSV(csv);
  const filtered = result.filter(() => true);
  assertEqual(filtered.length, 3, "all match");
});

test("filter with string predicate", () => {
  const csv = "fruit,color\napple,red\nbanana,yellow\ncherry,red";
  const result = parseCSV(csv);
  const reds = result.filter((row) => row["color"] === "red");
  assertEqual(reds.length, 2, "two reds");
});

test("filter with null handling", () => {
  const csv = "a,b\n1,hello\n2,\n3,world";
  const result = parseCSV(csv);
  const nonNull = result.filter((row) => row["b"] !== null);
  assertEqual(nonNull.length, 2, "two non-null");
});

test("filter with complex predicate", () => {
  const csv = "name,age,active\nAlice,30,true\nBob,25,false\nCharlie,35,true";
  const result = parseCSV(csv);
  const filtered = result.filter(
    (row) => (row["age"] as number) >= 30 && row["active"] === true
  );
  assertEqual(filtered.length, 2, "two matches");
  assertEqual(filtered[0]["name"], "Alice", "Alice");
  assertEqual(filtered[1]["name"], "Charlie", "Charlie");
});

