test("sum of column with all non-numeric values returns 0", () => {
  const csv = "val\nhello\nworld";
  const result = parseCSV(csv);
  assertEqual(result.sum("val"), 0, "sum is 0");
});

test("sum of nonexistent column returns 0", () => {
