// ── groupBy ──────────────────────────────────────────────────────────────────

section("Aggregation – groupBy");

test("groupBy groups rows by column value", () => {
  const csv = `dept,name
Engineering,Alice
Marketing,Bob
Engineering,Charlie
Marketing,Diana
Engineering,Eve`;
  const result = parseCSV(csv);
  const groups = result.groupBy("dept");

  assertEqual(groups.size, 2, "two groups");
  assertEqual(groups.get("Engineering")!.length, 3, "3 engineers");
  assertEqual(groups.get("Marketing")!.length, 2, "2 marketing");
});

test("groupBy with numeric column values", () => {
  const csv = "score,name\n90,Alice\n80,Bob\n90,Charlie";
  const result = parseCSV(csv);
  const groups = result.groupBy("score");
  assertEqual(groups.size, 2, "two distinct scores");
  assertEqual(groups.get(90)!.length, 2, "two with score 90");
  assertEqual(groups.get(80)!.length, 1, "one with score 80");
});

test("groupBy with null values", () => {
  const csv = "category,val\nA,1\n,2\nA,3\n,4";
  const result = parseCSV(csv);
  const groups = result.groupBy("category");
  assertEqual(groups.get("A")!.length, 2, "two in category A");
  assertEqual(groups.get(null)!.length, 2, "two with null category");
});

test("groupBy with boolean values", () => {
  const csv = "active,name\ntrue,Alice\nfalse,Bob\ntrue,Charlie";
  const result = parseCSV(csv);
  const groups = result.groupBy("active");
  assertEqual(groups.get(true)!.length, 2, "two active");
  assertEqual(groups.get(false)!.length, 1, "one inactive");
});

test("groupBy where every row is unique", () => {
  const csv = "id,val\n1,a\n2,b\n3,c";
  const result = parseCSV(csv);
  const groups = result.groupBy("id");
  assertEqual(groups.size, 3, "three groups");
  for (const [, rows] of groups) {
    assertEqual(rows.length, 1, "one row per group");
  }
});

