// 9. EDGE CASES
// ============================================================================
section("Edge Cases");

test("empty input returns empty result", () => {
  const result = parseCSV("");
  assertEqual(result.headers.length, 0, "no headers");
  assertEqual(result.rows.length, 0, "no rows");
  assertEqual(result.errors.length, 0, "no errors");
});

test("whitespace-only input returns empty result", () => {
  const result = parseCSV("   \n  \n  ");
  assertEqual(result.headers.length, 0, "no headers");
  assertEqual(result.rows.length, 0, "no rows");
});

test("single column CSV", () => {
  const csv = "value\n1\n2\n3";
  const result = parseCSV(csv);
  assertEqual(result.headers, ["value"], "one header");
  assertEqual(result.rows.length, 3, "three rows");
  assertEqual(result.rows[2]["value"], 3, "last value");
});

test("single row (header + one data row)", () => {
  const csv = "a,b,c\n1,2,3";
  const result = parseCSV(csv);
  assertEqual(result.rows.length, 1, "one row");
  assertEqual(result.rows[0]["b"], 2, "middle value");
});

test("header only, no data rows", () => {
  const csv = "a,b,c";
  const result = parseCSV(csv);
  assertEqual(result.headers, ["a", "b", "c"], "headers present");
  assertEqual(result.rows.length, 0, "no rows");
});

test("very large field", () => {
  const bigValue = "x".repeat(100_000);
  const csv = `data\n${bigValue}`;
  const result = parseCSV(csv);
  assertEqual(result.rows[0]["data"], bigValue, "large field preserved");
  assertEqual((result.rows[0]["data"] as string).length, 100_000, "correct length");
});

test("very large quoted field with commas", () => {
  // 1000 commas inside a quoted field
  const inner = Array.from({ length: 1000 }, (_, i) => `seg${i}`).join(",");
  const csv = `data\n"${inner}"`;
  const result = parseCSV(csv);
  assertEqual(result.rows[0]["data"], inner, "large quoted field");
});

test("many columns", () => {
  const n = 200;
  const headers = Array.from({ length: n }, (_, i) => `col${i}`).join(",");
  const values = Array.from({ length: n }, (_, i) => String(i)).join(",");
  const csv = `${headers}\n${values}`;
  const result = parseCSV(csv);
  assertEqual(result.headers.length, n, "200 headers");
  assertEqual(result.rows[0]["col0"], 0, "first col");
  assertEqual(result.rows[0]["col199"], 199, "last col");
});

test("many rows", () => {
  const lines = ["id"];
  for (let i = 0; i < 10_000; i++) {
    lines.push(String(i));
  }
  const csv = lines.join("\n");
  const result = parseCSV(csv);
  assertEqual(result.rows.length, 10_000, "10k rows");
  assertEqual(result.rows[9999]["id"], 9999, "last row");
});

test("field with only whitespace is not coerced to null", () => {
  const csv = "val\n   ";
  const result = parseCSV(csv);
  // "   " is not "" or "null" or "NULL", so it stays as string
  assertEqual(typeof result.rows[0]["val"], "string", "whitespace stays string");
});

test("empty unquoted fields become null with coercion", () => {
  const csv = "a,b,c\n,,";
  const result = parseCSV(csv);
  assertEqual(result.rows[0]["a"], null, "empty → null");
  assertEqual(result.rows[0]["b"], null, "empty → null");
