// ============================================================================
// CSV Parser Library
// ============================================================================

/** Configuration options for the CSV parser */
export interface CSVOptions {
  /** Field delimiter character (default: ',') */
  delimiter?: string;
  /** Quote character for wrapping fields (default: '"') */
  quote?: string;
  /** Line separator (default: auto-detect \r\n, \n, or \r) */
  lineSeparator?: string;
  /** Whether to automatically coerce types (default: true) */
  typeCoercion?: boolean;
}

/** Represents a parsing error on a specific row */
export interface CSVError {
  row: number;
  message: string;
}

/** A single parsed row as a record of header -> value */
export type CSVRow = Record<string, unknown>;

/** The result returned by parseCSV */
export interface CSVResult {
  /** Parsed data rows as an array of objects keyed by header names */
  rows: CSVRow[];
  /** The column header names */
  headers: string[];
  /** Any errors encountered during parsing (malformed rows, etc.) */
  errors: CSVError[];

  /**
   * Filter rows by a predicate function.
   * Returns a new array of rows matching the predicate.
   */
  filter(predicate: (row: CSVRow) => boolean): CSVRow[];

  /**
   * Sum all numeric values in a given column.
   * Non-numeric and null values are ignored.
   */
  sum(column: string): number;

  /**
   * Average all numeric values in a given column.
   * Non-numeric and null values are ignored.
   * Returns NaN if no numeric values exist.
   */
  average(column: string): number;

  /** Count the total number of parsed rows. */
  count(): number;

  /**
   * Group rows by the values in a given column.
   * Returns a Map where each key is a distinct column value
   * and each value is the array of rows sharing that value.
   */
  groupBy(column: string): Map<unknown, CSVRow[]>;
}

// ============================================================================
// Internal: Field-level parser (handles quoting, escaping, delimiters)
// ============================================================================

/**
 * Parse a single CSV line into an array of string field values.
 * Handles quoted fields, escaped quotes (doubled quote chars), and
 * fields containing delimiters or newlines within quotes.
 *
 * This is a character-by-character state machine.
 */
function parseFields(
  line: string,
  delimiter: string,
  quote: string
): { fields: string[]; error: string | null } {
  const fields: string[] = [];
  let current = "";
  let inQuotes = false;
  let i = 0;
  let error: string | null = null;

  while (i < line.length) {
    const ch = line[i];

    if (inQuotes) {
      if (ch === quote) {
        // Look ahead: is the next char also a quote? → escaped quote
        if (i + 1 < line.length && line[i + 1] === quote) {
          current += quote;
          i += 2;
          continue;
        }
        // End of quoted field
        inQuotes = false;
        i++;
        // After closing quote we expect delimiter or end of line
        if (i < line.length && line[i] !== delimiter) {
          error = `Unexpected character '${line[i]}' after closing quote at position ${i}`;
          // Try to recover: skip until next delimiter or end
          while (i < line.length && line[i] !== delimiter) {
            current += line[i];
            i++;
          }
        }
        continue;
      }
      // Regular character inside quotes
      current += ch;
      i++;
    } else {
      if (ch === quote) {
        if (current.length === 0) {
          // Start of a quoted field
          inQuotes = true;
          i++;
        } else {
          // Quote in the middle of an unquoted field – treat as literal but flag error
          error = `Unexpected quote character at position ${i} in unquoted field`;
          current += ch;
          i++;
        }
      } else if (ch === delimiter) {
        fields.push(current);
        current = "";
        i++;
      } else {
        current += ch;
        i++;
      }
    }
  }

  // If we're still inside quotes at end-of-line, that's an error
  if (inQuotes) {
    error = `Unterminated quoted field`;
  }

  // Push the last field
  fields.push(current);

  return { fields, error };
}

// ============================================================================
// Internal: Type coercion
// ============================================================================

/**
 * Attempt to coerce a raw string value to a richer JS type.
 * Priority: null → boolean → number → string
 */
function coerceValue(raw: string): unknown {
  // Null detection: empty string, "null", "NULL"
  if (raw === "" || raw === "null" || raw === "NULL") {
    return null;
  }

  // Boolean detection (case-insensitive)
  const lower = raw.toLowerCase();
  if (lower === "true") return true;
  if (lower === "false") return false;

  // Number detection
  // We need to be careful: don't coerce strings like "" or whitespace-only.
  // Also avoid treating strings like "0x10" or "Infinity" as numbers unless
  // they genuinely look like decimal numbers.
  const trimmed = raw.trim();
  if (trimmed.length > 0 && /^-?(\d+\.?\d*|\.\d+)([eE][+-]?\d+)?$/.test(trimmed)) {
    const num = Number(trimmed);
    if (!isNaN(num)) {
      return num;
    }
  }

  return raw;
}

// ============================================================================
// Internal: Line splitting (respects quoted fields spanning lines)
// ============================================================================

/**
 * Split raw CSV text into logical lines, correctly handling quoted fields
 * that span multiple physical lines.
 */
function splitLogicalLines(
  input: string,
  lineSeparator: string | undefined,
  quote: string
): string[] {
  // If a specific line separator was given, we use a smarter approach
  // that still respects quotes.

  // Determine the actual separator to scan for.
  // If not specified, we auto-detect from the input.
  let sep: string;
  if (lineSeparator) {
    sep = lineSeparator;
  } else {
    // Auto-detect: prefer \r\n, then \n, then \r
    if (input.includes("\r\n")) {
      sep = "\r\n";
    } else if (input.includes("\n")) {
      sep = "\n";
    } else if (input.includes("\r")) {
      sep = "\r";
    } else {
      // Single line
      sep = "\n";
    }
  }

  const lines: string[] = [];
  let current = "";
  let inQuotes = false;
  let i = 0;

  while (i < input.length) {
    // Check for line separator
    if (!inQuotes && input.substring(i, i + sep.length) === sep) {
      lines.push(current);
      current = "";
      i += sep.length;
      continue;
    }

    const ch = input[i];

    if (ch === quote) {
      // Toggle quote state (handle escaped quotes)
      if (inQuotes && i + 1 < input.length && input[i + 1] === quote) {
        // Escaped quote – stays in quotes
        current += ch + input[i + 1];
        i += 2;
        continue;
      }
      inQuotes = !inQuotes;
    }

    current += ch;
    i++;
  }

  // Push final line
  if (current.length > 0) {
    lines.push(current);
  }

  return lines;
}

// ============================================================================
// Public API: parseCSV
// ============================================================================

/**
 * Parse a CSV string into a structured result with rows, headers, errors,
 * and convenience methods for filtering and aggregation.
 */
export function parseCSV(input: string, options?: CSVOptions): CSVResult {
  const delimiter = options?.delimiter ?? ",";
  const quote = options?.quote ?? '"';
  const lineSeparator = options?.lineSeparator;
  const typeCoercion = options?.typeCoercion ?? true;

  const rows: CSVRow[] = [];
  const errors: CSVError[] = [];

  // Handle empty / whitespace-only input
  if (!input || input.trim().length === 0) {
    return buildResult([], [], errors);
  }

  // Split into logical lines (respecting multi-line quoted fields)
  const lines = splitLogicalLines(input, lineSeparator, quote);

  if (lines.length === 0) {
    return buildResult([], [], errors);
  }

  // First line is headers
  const headerParse = parseFields(lines[0], delimiter, quote);
  const headers = headerParse.fields.map((h) => h.trim());

  if (headerParse.error) {
    errors.push({ row: 0, message: `Header row: ${headerParse.error}` });
  }

  // Parse data rows
  for (let rowIdx = 1; rowIdx < lines.length; rowIdx++) {
    const line = lines[rowIdx];

    // Skip completely empty lines
    if (line.trim().length === 0) continue;

    const { fields, error } = parseFields(line, delimiter, quote);

    if (error) {
      errors.push({ row: rowIdx, message: error });
      // Still attempt to include the row (best-effort recovery)
    }

    // Check field count mismatch
    if (fields.length !== headers.length) {
      errors.push({
        row: rowIdx,
        message: `Expected ${headers.length} fields but got ${fields.length}`,
      });

      // Best-effort: if fewer fields, pad with null; if more, truncate
      // We still produce a row so consumers can inspect partial data.
    }

    const row: CSVRow = {};
    for (let col = 0; col < headers.length; col++) {
      const rawValue = col < fields.length ? fields[col] : "";
      row[headers[col]] = typeCoercion ? coerceValue(rawValue) : rawValue;
    }

    rows.push(row);
  }

  return buildResult(headers, rows, errors);
}

// ============================================================================
// Internal: Build the result object with attached methods
// ============================================================================

function buildResult(
  headers: string[],
  rows: CSVRow[],
  errors: CSVError[]
): CSVResult {
  return {
    headers,
    rows,
    errors,

    filter(predicate: (row: CSVRow) => boolean): CSVRow[] {
      return rows.filter(predicate);
    },

    sum(column: string): number {
      let total = 0;
      for (const row of rows) {
        const val = row[column];
        if (typeof val === "number") {
          total += val;
        }
      }
      return total;
    },

    average(column: string): number {
      let total = 0;
      let count = 0;
      for (const row of rows) {
        const val = row[column];
        if (typeof val === "number") {
          total += val;
          count++;
        }
      }
      return count === 0 ? NaN : total / count;
    },

    count(): number {
      return rows.length;
    },

    groupBy(column: string): Map<unknown, CSVRow[]> {
      const map = new Map<unknown, CSVRow[]>();
      for (const row of rows) {
        const key = row[column];
        if (!map.has(key)) {
          map.set(key, []);
        }
        map.get(key)!.push(row);
      }
      return map;
    },
  };
}
